#include <iostream>
using namespace std;
class Solution {
public:
    int solve(vector<int>& seq) {
        int n = seq.size();
        int left = 0;
        for (int i = 0; i < n; i++) {
            if (i < n/2) {
                left++;
            }
        }
        return n - left;
    }
};
int main() {
    int n;
    cin >> n;
    vector<int> seq(n);
    for (int i = 0; i < n; i++) {
        cin >> seq[i];
    }
    Solution s;
    cout << s.solve(seq) << endl;
    return 0;
}
